import anthropic
import httpx
import json
from dataclasses import dataclass, field

@dataclass
class Paper:
    title: str
    abstract: str
    authors: list[str]
    year: int
    url: str
    included: bool = False
    exclusion_reason: str = ""
    extracted_data: dict = field(default_factory=dict)

class LiteratureReviewAgent:
    def __init__(self, research_question: str, inclusion_criteria: dict):
        self.research_question = research_question
        self.inclusion = inclusion_criteria
        self.client = anthropic.Anthropic()
        self.papers: list[Paper] = []

    def build_pubmed_query(self) -> str:
        """Generate a PubMed Boolean query from the research question."""
        response = self.client.messages.create(
            model="claude-opus-4-5",
            max_tokens=512,
            messages=[{"role": "user", "content": f"""
Convert this research question to a PubMed Boolean search string using MeSH terms.
Return ONLY the query string, nothing else.

Research question: {self.research_question}
Inclusion: {json.dumps(self.inclusion)}
"""}]
        )
        return response.content[0].text.strip()

    def search_pubmed(self, query: str, max_results: int = 200) -> list[Paper]:
        """Search PubMed via E-utilities API."""
        search_resp = httpx.get(
            "https://eutils.ncbi.nlm.nih.gov/entrez/eutils/esearch.fcgi",
            params={"db": "pubmed", "term": query, "retmax": max_results,
                    "retmode": "json", "sort": "relevance"},
            timeout=30,
        )
        ids = search_resp.json()["esearchresult"]["idlist"]

        # Fetch abstracts in batches
        papers = []
        for i in range(0, len(ids), 20):
            batch = ids[i:i+20]
            fetch_resp = httpx.get(
                "https://eutils.ncbi.nlm.nih.gov/entrez/eutils/efetch.fcgi",
                params={"db": "pubmed", "id": ",".join(batch),
                        "rettype": "abstract", "retmode": "json"},
                timeout=30,
            )
            # Parse PubMed XML response (simplified)
            for pmid in batch:
                papers.append(Paper(
                    title=f"PubMed paper {pmid}",  # actual XML parsing needed
                    abstract="Abstract text from PubMed fetch...",
                    authors=[], year=2024,
                    url=f"https://pubmed.ncbi.nlm.nih.gov/{pmid}/",
                ))
        return papers

    def screen_abstract(self, paper: Paper) -> tuple[bool, str]:
        """Apply inclusion/exclusion criteria to title + abstract."""
        response = self.client.messages.create(
            model="claude-opus-4-5",
            max_tokens=256,
            messages=[{"role": "user", "content": f"""
Screen this paper for inclusion in a systematic review.

Research question: {self.research_question}
Inclusion criteria: {json.dumps(self.inclusion)}

Title: {paper.title}
Abstract: {paper.abstract[:1000]}

Return JSON: {{"include": true/false, "reason": "brief justification"}}
"""}]
        )
        text = response.content[0].text
        result = json.loads(text[text.find("{"):text.rfind("}")+1])
        return result["include"], result.get("reason", "")

    def extract_data(self, paper: Paper, full_text: str) -> dict:
        """Extract structured data fields from full text."""
        response = self.client.messages.create(
            model="claude-opus-4-5",
            max_tokens=512,
            messages=[{"role": "user", "content": f"""
Extract structured data from this paper. Return JSON with:
- study_design, population, n, intervention, comparator, outcomes, effect_size, risk_of_bias

Title: {paper.title}
Text: {full_text[:3000]}
"""}]
        )
        text = response.content[0].text
        try:
            return json.loads(text[text.find("{"):text.rfind("}")+1])
        except Exception:
            return {"raw": text[:200]}

    def run(self, max_papers: int = 200) -> str:
        query = self.build_pubmed_query()
        print(f"PubMed query: {query}")

        self.papers = self.search_pubmed(query, max_results=max_papers)
        print(f"Retrieved {len(self.papers)} papers")

        included = []
        for paper in self.papers:
            include, reason = self.screen_abstract(paper)
            paper.included = include
            paper.exclusion_reason = reason if not include else ""
            if include:
                included.append(paper)

        print(f"Included after screening: {len(included)}")

        # Generate synthesis report
        evidence_summary = "
".join([
            f"- {p.title} ({p.year}): {json.dumps(p.extracted_data)}"
            for p in included[:30]
        ])
        response = self.client.messages.create(
            model="claude-opus-4-5",
            max_tokens=4096,
            messages=[{"role": "user", "content": f"""
Write a systematic review synthesis for: {self.research_question}

Included papers: {len(included)}
Evidence summary:
{evidence_summary}

Structure: Background, Methods, Results (by theme), Discussion, Conclusion
Include PRISMA flow numbers.
"""}]
        )
        return response.content[0].text

# Usage
agent = LiteratureReviewAgent(
    research_question="Effectiveness of cognitive behavioural therapy for insomnia in adults",
    inclusion_criteria={
        "study_design": ["RCT", "quasi-RCT"],
        "population": "adults with insomnia disorder",
        "intervention": "CBT-I",
        "language": "English",
        "year_from": 2010,
    }
)
report = agent.run(max_papers=500)
print(report)
